local CustomShop = {}

local function init()
    local config = FileUtil.getConfigFromCsv("setting/CustomShopTabs.csv")
    local tabs = {}
    for _, item in pairs(config) do
        tabs[item.TabId] = {
            Type = tonumber(item.Type),
            TabId = tonumber(item.TabId),
            EquipCount = tonumber(item.EquipCount),
            TypeLang = item.TypeLang,
            Icon = item.Icon,
            Lang = item.Lang,
            GoodsList = {},
            Weight = tonumber(item.Weight) or 1,
            ModelType = tonumber(item.ModelType)
        }
    end
    config = FileUtil.getConfigFromCsv("setting/CustomShopGoods.csv")
    for _, item in pairs(config) do
        local tab = tabs[item.TabId]
        if tab then
            local goods = {
                Id = tonumber(item.Id),
                TabId = tonumber(item.TabId),
                Price = tonumber(item.Price),
                Name = item.Name,
                Image = item.Image,
                Time = tonumber(item.Time) or -1,
                GetWay = tonumber(item.GetWay) or 1,
                SettingId = item.SettingId,
                Default = item.Default == "1",
                Weight = tonumber(item.Weight) or 1
            }
            if item.DiscountPrices == nil or item.DiscountPrices == "#" then
                goods.DiscountPrices = goods.Price
            else
                goods.DiscountPrices = tonumber(item.DiscountPrices) or goods.Price
            end
            if isClient then
                goods.Time = 0
            end
            table.insert(tab.GoodsList, goods)
        end
    end
    for _, tab in pairs(tabs) do
        local _tabs = CustomShop[tostring(tab.Type)] or {}
        table.insert(_tabs, tab)
        CustomShop[tostring(tab.Type)] = _tabs
    end
    for _, _tabs in pairs(CustomShop) do
        table.sort(_tabs, function(a, b)
            return a.Weight < b.Weight
        end)
        for _, tab in pairs(_tabs) do
            table.sort(tab.GoodsList, function(a, b)
                return a.Weight < b.Weight
            end)
        end
    end
end

init()

CustomShopConfig = {}

function CustomShopConfig:getCustomShop()
    local items = {}
    for type, tabs in pairs(CustomShop) do
        table.insert(items, {
            min_weight = tabs[1].Weight,
            type = tonumber(type),
            tabs = tabs
        })
    end
    table.sort(items, function(a, b)
        return a.min_weight < b.min_weight
    end)
    return items
end

function CustomShopConfig:getGoodsList(tabId)
    for _, tabs in pairs(CustomShop) do
        for _, tab in pairs(tabs) do
            if tab.TabId == tabId then
                return tab.GoodsList
            end
        end
    end
    return {}
end

function CustomShopConfig:getGoodsListByType(type)
